// ============================================================
// DISPATCHER CODE NODE v4.0
// Cross-JOIN + Filtro Día + Detección Automática de Semana
// + RAG Cache forwarding between loop iterations
// ============================================================

const temasItems  = $('GSheets - Temas').all();
const sitiosItems = $('GSheets - Sitios').all();
const perfilesItems = $('GSheets - Perfiles').all();

// ---- 1. Calcular el LUNES de la semana actual ----
const now = new Date();
const dayOfWeek = now.getDay();
const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
const monday = new Date(now);
monday.setDate(now.getDate() + diffToMonday);
const mondayISO = monday.toISOString().split('T')[0];

// ---- 2. Normalizar fecha a ISO ----
function normalizeDateToISO(raw) {
  if (!raw) return '';
  const str = String(raw).trim();
  if (/^\d{4}-\d{2}-\d{2}/.test(str)) return str.substring(0, 10);
  if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(str)) {
    const [m, d, y] = str.split('/');
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
  }
  if (/^\d{1,2}-\d{1,2}-\d{4}$/.test(str)) {
    const [d, m, y] = str.split('-');
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
  }
  if (/^\d{5}$/.test(str)) {
    const epoch = new Date(1899, 11, 30);
    epoch.setDate(epoch.getDate() + parseInt(str));
    return epoch.toISOString().split('T')[0];
  }
  try {
    const parsed = new Date(str);
    if (!isNaN(parsed.getTime())) return parsed.toISOString().split('T')[0];
  } catch (e) {}
  return str;
}

// ---- 3. Encontrar el tema de ESTA semana ----
const tema = temasItems.find(i => {
  return normalizeDateToISO(i.json.Fecha_Lunes_Referencia) === mondayISO;
})?.json;

if (!tema) {
  console.log(`⚠️ No se encontró tema para la semana del ${mondayISO}`);
  console.log(`   Fechas disponibles: ${temasItems.map(i => i.json.Fecha_Lunes_Referencia).join(', ')}`);
  return [];
}

// ---- 4. Detectar el día de HOY ----
const hoy = new Date()
  .toLocaleDateString('es-MX', { weekday: 'long' })
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

const fechaHoy = new Date().toISOString().split('T')[0];

// ---- 5. Filtrar sitios activos que publican HOY ----
const sitiosHoy = sitiosItems.filter(s => {
  const diaSitio = (s.json.Dia_Publicacion || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
  return diaSitio === hoy && String(s.json.activo).toUpperCase() === 'TRUE';
});

if (sitiosHoy.length === 0) return [];

// ---- 6. Cross-JOIN → payload (rag_cache starts as null) ----
return sitiosHoy.map(s => {
  const site = s.json;
  const perfil = perfilesItems.find(
    p => p.json.perfil_id === site.perfil_id
  )?.json || {};

  const idiomaInstruccion = site.idioma === 'es' ? 'español neutro' : 'English';

  let systemPromptFinal = perfil.system_prompt_template || '';
  const replacements = {
    '{{AUTHOR_NAME}}':        perfil.author_name || '',
    '{{AUTHOR_TITLE}}':       perfil.author_title || '',
    '{{AUTHOR_BIO}}':         perfil.author_bio || '',
    '{{IDIOMA_INSTRUCCION}}': idiomaInstruccion,
    '{{PUBLISHER_NAME}}':     site.publisher_name || '',
    '{{PUBLISHER_URL}}':      site.wp_url || '',
    '{{CATEGORY_URL}}':       site.category_url || '',
    '{{CTA_COPY}}':           site.cta_copy || '',
  };
  for (const [token, value] of Object.entries(replacements)) {
    systemPromptFinal = systemPromptFinal.split(token).join(value);
  }

  return { json: {
    site_id:              site.site_id,
    wp_url:               site.wp_url,
    wp_user:              site.wp_user,
    wp_app_password:      site.wp_app_password,
    tema_semanal:         tema.Tema_Principal || '',
    angulo_enfoque:       tema.Angulo_Enfoque || '',
    idioma:               site.idioma,
    system_prompt_final:           systemPromptFinal,
    art_director_system_prompt:    perfil.art_director_system_prompt || '',
    author_name:          perfil.author_name || '',
    author_title:         perfil.author_title || '',
    author_bio:           perfil.author_bio || '',
    publisher_name:       site.publisher_name || '',
    publisher_url:        site.wp_url || '',
    category_url:         site.category_url || '',
    cta_copy:             site.cta_copy || '',
    wp_scheduled_date:    `${fechaHoy}T${site.Hora_Publicacion || '07:00'}:00`,
    rag_cache:            null,
    _debug_semana_detectada: mondayISO,
    _debug_dia_detectado:    hoy,
  }};
});

// ============================================================
// FORWARD RAG CACHE — v4.0
// ============================================================
// After each Worker execution, this node captures the rag_cache
// returned by WF2 and injects it into the NEXT item in the
// Split in Batches queue.
//
// HOW IT WORKS:
// 1. Worker returns { success, post_id, ..., rag_cache: {...} }
// 2. This node reads that rag_cache
// 3. Uses n8n's static data to store it between iterations
// 4. On the next loop, the Cross-JOIN payload already has
//    rag_cache: null, but the "Inject Cache" node will
//    overwrite it with the stored cache before calling Worker
// ============================================================

const workerOutput = $json;

// Store rag_cache in workflow static data (persists across loop iterations)
const staticData = $getWorkflowStaticData('global');

if (workerOutput.rag_cache) {
  staticData.rag_cache = workerOutput.rag_cache;
}

// Log for debugging
const hasCacheNow = !!staticData.rag_cache;
console.log(`[RAG Cache] Site: ${workerOutput.site_id || 'unknown'} | Post: ${workerOutput.post_id || 'N/A'} | Cache stored: ${hasCacheNow}`);

// Pass through the worker result (for logging/monitoring)
return [{ json: {
  ...workerOutput,
  _cache_forwarded: hasCacheNow
}}];

// ============================================================
// INJECT RAG CACHE — v4.0
// ============================================================
// Runs BEFORE calling the Worker on each batch item.
// Reads the cached RAG data from static data (stored after
// the previous Worker call) and injects it into the payload.
//
// First iteration: no cache → Worker runs full RAG pipeline
// Subsequent iterations: cache exists → Worker skips RAG agents
// ============================================================

const item = $json;
const staticData = $getWorkflowStaticData('global');

// Inject cached RAG data if available
if (staticData.rag_cache) {
  item.rag_cache = staticData.rag_cache;
  console.log(`[RAG Inject] Injecting cache for site: ${item.site_id} (saving ~12K tokens + 3 Pinecone queries)`);
} else {
  console.log(`[RAG Inject] No cache yet for site: ${item.site_id} — Worker will run full RAG pipeline`);
}

return [{ json: item }];

// ============================================================
// SUMMARY LOG — v4.0
// ============================================================
// Final node: summarizes all published posts and cache status.
// Clears the static RAG cache for next execution.
// ============================================================

const allResults = $input.all();
const staticData = $getWorkflowStaticData('global');

// Clear cache for next scheduled run
delete staticData.rag_cache;

const summary = allResults.map(item => {
  const d = item.json;
  return {
    site_id: d.site_id || 'unknown',
    post_id: d.post_id || 'N/A',
    post_url: d.post_url || '',
    success: d.success || false,
    cache_used: d._cache_forwarded || false
  };
});

const total = summary.length;
const succeeded = summary.filter(s => s.success).length;
const cached = summary.filter(s => s.cache_used).length;

console.log(`\n═══ DISPATCHER v4.0 SUMMARY ═══`);
console.log(`Total sites: ${total}`);
console.log(`Succeeded: ${succeeded}`);
console.log(`Used RAG cache: ${cached} (saved ~${cached * 12}K Claude tokens)`);
console.log(`═══════════════════════════════\n`);

return [{ json: {
  dispatcher_version: '4.0',
  total_sites: total,
  succeeded: succeeded,
  cache_hits: cached,
  estimated_tokens_saved: cached * 12000,
  details: summary
}}];
